import { useHeaderHeight } from '@react-navigation/elements'
import type { LoadError, Rect } from '@react-pdf-viewer/core'
import { Worker, Viewer, SpecialZoomLevel, ScrollMode } from '@react-pdf-viewer/core'
import { scrollModePlugin } from '@react-pdf-viewer/scroll-mode'
import { useCallback, useEffect } from 'react'
import { View, useWindowDimensions } from 'react-native'
import { ActivityIndicator, useTheme } from 'react-native-paper'
import '@react-pdf-viewer/core/lib/styles/index.css'

import './CatalogueViewerReactPdf.web.css'
import type { CatalogueViewerProps } from './types'
import { useStyles } from '../../utils/useStyles'

export type CatalogueViewerReactPdfProps = CatalogueViewerProps

export const CatalogueViewerReactPdf = ({
  uri,
  page,
  onPageChanged,
  horizontal,
}: CatalogueViewerReactPdfProps) => {
  const { width: windowWidth, height: windowHeight } = useWindowDimensions()
  const headerHeight = useHeaderHeight()
  const { dark } = useTheme()

  const styles = useStyles(
    ({ dark }) => ({
      main: {
        height: windowHeight - headerHeight,
        width: windowWidth,
        justifyContent: 'center',
      },
    }),
    [windowHeight, headerHeight, windowWidth],
  )

  const scrollModePluginInstance = scrollModePlugin()
  // eslint-disable-next-line @typescript-eslint/unbound-method
  const { switchScrollMode } = scrollModePluginInstance

  const handleRenderError = useCallback(({ message, name }: LoadError) => {
    throw new Error(`${name} - ${message}`)
  }, [])

  const handleRenderLoader = useCallback((percentages: number) => {
    return <ActivityIndicator size="large" />
  }, [])

  const handleTransformSize = useCallback(
    ({ size }: { size: Rect }) => ({
      height: size.height + 30,
      width: size.width + 30,
    }),
    [],
  )

  useEffect(() => {
    switchScrollMode(horizontal ? ScrollMode.Horizontal : ScrollMode.Vertical)
  }, [horizontal, switchScrollMode])

  if (!process.env.EXPO_PUBLIC_PDFJS_WORKER_URL) {
    throw new Error('missing pdfjs worker url')
  }

  return (
    <Worker workerUrl={process.env.EXPO_PUBLIC_PDFJS_WORKER_URL}>
      <View style={styles.main}>
        <Viewer
          plugins={[scrollModePluginInstance]}
          initialPage={page - 1}
          theme={{ theme: dark ? 'dark' : 'light' }}
          renderError={handleRenderError}
          fileUrl={uri}
          renderLoader={handleRenderLoader}
          defaultScale={SpecialZoomLevel.PageFit}
          pageLayout={{ transformSize: handleTransformSize }}
          onPageChange={({ currentPage, doc }) =>
            onPageChanged ? onPageChanged(currentPage + 1, doc.numPages) : null
          }
        />
      </View>
    </Worker>
  )
}

export default CatalogueViewerReactPdf
